export const usePayment = () => {
  const context = useContext(PaymentContext);
  if (!context) throw new Error('usePayment must be used within a PaymentProvider');
  return context;
};

export const PaymentButton = ({
  type = 'wallet',
  productId,
  amount,
  currency,
  provider,
  merchantId,
  description,
  quantity = 1,
  offerToken = null,
  metadata = {},
  onSuccess,
  onError,
  title,
  style,
  textStyle,
  disabled,
}) => {
  const { processing, processInAppPurchase, processDigitalWalletTransaction } = usePayment();

  const handlePress = useCallback(async () => {
    try {
      let result;
      if (type === 'iap') {
        result = await processInAppPurchase({ productId, quantity, offerToken, metadata });
      } else {
        result = await processDigitalWalletTransaction({
          provider,
          amount,
          currency,
          merchantId,
          description,
          metadata,
        });
      }
      onSuccess?.(result);
    } catch (e) {
      const normalized = normalizeError(e);
      onError?.(normalized);
      Alert.alert('Payment Error', normalized.message);
    }
  }, [
    amount,
    currency,
    description,
    merchantId,
    metadata,
    onError,
    onSuccess,
    offerToken,
    processDigitalWalletTransaction,
    processInAppPurchase,
    productId,
    provider,
    quantity,
    type,
  ]);

  return React.createElement(
    'TouchableOpacity',
    {
      onPress: handlePress,
      disabled: disabled || processing,
      style: style || {
        backgroundColor: disabled || processing ? '#999' : '#111',
        paddingVertical: 14,
        paddingHorizontal: 18,
        borderRadius: 10,
        alignItems: 'center',
        justifyContent: 'center',
        opacity: disabled || processing ? 0.7 : 1,
      },
      accessibilityRole: 'button',
      accessibilityLabel: title || 'Pay',
    },
    React.createElement(
      'Text',
      { style: textStyle || { color: '#fff', fontWeight: '600' } },
      processing ? 'Processing...' : (title || (type === 'iap' ? 'Buy' : 'Pay Now'))
    )
  );
};

export const PaymentStatus = ({ style, textStyle }) => {
  const { initialized, processing, error, lastTransaction, sessionValid, securityStatus } = usePayment();

  const statusText = !initialized
    ? 'Initializing payment services...'
    : !sessionValid
      ? 'Session expired'
      : processing
        ? 'Processing payment...'
        : error
          ? `Error: ${error.message}`
          : lastTransaction
            ? `Last transaction: ${lastTransaction.status}`
            : 'Ready';

  return React.createElement(
    'View',
    { style: style || { padding: 12 } },
    React.createElement('Text', { style: textStyle || { color: '#333' } }, statusText),
    React.createElement(
      'Text',
      { style: { color: '#666', marginTop: 4, fontSize: 12 } },
      `Biometrics: ${securityStatus.biometricsAvailable ? 'Available' : 'Unavailable'} | Tokenization: ${securityStatus.tokenizationReady ? 'Ready' : 'Unavailable'}`
    )
  );
};

